-- Update articles with rich content and images

-- Article 1: Fund Recovery Guide
UPDATE articles SET
  featured_image = 'https://images.pexels.com/photos/4386369/pexels-photo-4386369.jpeg?auto=compress&cs=tinysrgb&w=1200',
  excerpt = 'تعرف على الخطوات العملية لاسترداد الأموال من شركات الفوركس المحتالة، بدءًا من جمع الأدلة والتواصل مع البنك وصولًا إلى تقديم الشكاوى والاستعانة بالجهات المختصة. دليل شامل مدعم بالصور والنصائح العملية.',
  content = '<h2>مقدمة: لماذا هذا الدليل مهم لكل متداول؟</h2><p>التعرض للاحتيال من قبل شركة فوركس غير موثوقة تجربة صعبة قد تؤدي إلى خسائر مالية كبيرة. لكن ذلك لا يعني بالضرورة أن أموالك قد ضاعت إلى الأبد.</p><img src="https://images.pexels.com/photos/4386369/pexels-photo-4386369.jpeg?auto=compress&cs=tinysrgb&w=800" alt="استرداد الأموال" class="w-full rounded-xl my-6" /><p>في هذا الدليل الشامل، سنتعرف على الخطوات الأساسية لاسترداد الأموال من شركات الفوركس المحتالة.</p><h2>الفهم الأساسي: كيف تعمل شركات الفوركس المحتالة؟</h2><p>قبل الخوض في عملية الاسترداد، من الضروري فهم آلية عمل هذه الشركات:</p><h3>1. شركات الكتب المزيفة (Bucket Shops)</h3><p>هذه الشركات لا توصل صفقاتك إلى السوق الحقيقي. بدلاً من ذلك، تأخذ الجانب الآخر من صفقاتك.</p><img src="https://images.pexels.com/photos/534216/pexels-photo-534216.jpeg?auto=compress&cs=tinysrgb&w=800" alt="تداول الفوركس" class="w-full rounded-xl my-6" /><h3>2. مخططات بونزي</h3><p>تعدك هذه الشركات بعوائد شهرية عالية وثابتة. في البداية، يدفعون لك من أموال المستثمرين الجدد.</p><h3>3. منصات التداول المزيفة</h3><p>تعرض منصة تبدو حقيقية لكنها تعمل ببيانات مزيفة.</p><h2>العلامات التحذيرية المبكرة</h2><div class="bg-red-50 border-r-4 border-red-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-red-800 mb-2">علامة خطر رقم 1: صعوبة السحب</h4><p class="text-gray-700">إذا كانت الشركة تماطل في طلبات السحب، فهذه علامة تحذيرية كبرى.</p></div><div class="bg-red-50 border-r-4 border-red-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-red-800 mb-2">علامة خطر رقم 2: وعود أرباح مضمونة</h4><p class="text-gray-700">لا توجد أرباح مضمونة في التداول.</p></div><img src="https://images.pexels.com/photos/6801648/pexels-photo-6801648.jpeg?auto=compress&cs=tinysrgb&w=800" alt="تحذيرات الفوركس" class="w-full rounded-xl my-6" /><h2>الخطوة الأولى: التوقف الفوري عن إرسال أي أموال</h2><p>يقع العديد من الضحايا في خطأ دفع رسوم إضافية بناءً على وعود كاذبة.</p><ul><li><strong>ضريبة الأرباح:</strong> يدّعون أنك بحاجة لدفع ضريبة قبل السحب</li><li><strong>رسوم التحويل:</strong> يطلبون رسومًا باهظة</li><li><strong>تأكيد الحساب:</strong> يطلبون إيداع لتأكيد الهوية</li></ul><div class="bg-amber-50 border-r-4 border-amber-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-amber-800 mb-2">قاعدة ذهبية</h4><p class="text-gray-700">لا تدفع أي مبلغ إضافي لشركة ترفض سحب أموالك الأصلية.</p></div><h2>الخطوة الثانية: جمع الأدلة بشكل منهجي</h2><p>نجاح عملية الاسترداد يعتمد على جودة الأدلة:</p><img src="https://images.pexels.com/photos/546819/pexels-photo-546819.jpeg?auto=compress&cs=tinysrgb&w=800" alt="جمع الأدلة" class="w-full rounded-xl my-6" /><h3>المستندات المالية</h3><ul><li>إيصالات جميع التحويلات البنكية</li><li>كشوفات حساب بنكي</li><li>سجلات بطاقات الائتمان</li></ul><h3>التوثيق الرقمي</h3><ul><li>لقطات شاشة للرصيد</li><li>صور لسجل الصفقات</li><li>تسجيل طلبات السحب المرفوضة</li></ul><h3>التواصل</h3><ul><li>تصدير محادثات واتساب وتيليجرام</li><li>حفظ جميع الإيميلات</li><li>تسجيل المكالمات الهاتفية</li></ul><h2>الخطوة الثالثة: تقديم طلب سحب رسمي</h2><img src="https://images.pexels.com/photos/6611418/pexels-photo-6611418.jpeg?auto=compress&cs=tinysrgb&w=800" alt="طلب السحب" class="w-full rounded-xl my-6" /><ol><li><strong>إثبات المحاولة:</strong> تاريخ طلب السحب يثبت محاولتك</li><li><strong>توثيق الرفض:</strong> رد الشركة دليل قوي</li><li><strong>متطلب للشكاوى:</strong> الجهات الرقابية تطلب الإثبات</li></ol><h2>الخطوة الرابعة: التواصل مع البنك</h2><p>إذا تم الإيداع ببطاقة، يمكنك طلب Chargeback.</p><h3>ما هو Chargeback؟</h3><p>عملية لاسترداد الأموال من تاجر رفض تقديم الخدمة.</p><h3>شروط نجاح Chargeback:</h3><ul><li>إثبات أن الخدمة لم تُقدَّم</li><li>إثبات محاولة التواصل مع التاجر</li><li>أن تكون ضمن الإطار الزمني (120-540 يوم)</li></ul><div class="bg-blue-50 border-r-4 border-blue-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-blue-800 mb-2">نصيحة مهمة</h4><p class="text-gray-700">تواصل مع بنكك فوراً.</p></div><h2>الخطوة الخامسة: تقديم شكاوى للجهات الرقابية</h2><img src="https://images.pexels.com/photos/5668858/pexels-photo-5668858.jpeg?auto=compress&cs=tinysrgb&w=800" alt="الجهات الرقابية" class="w-full rounded-xl my-6" /><h3>الجهات الرقابية الرئيسية:</h3><ul><li><strong>FCA (بريطانيا)</strong></li><li><strong>ASIC (أستراليا)</strong></li><li><strong>CySEC (قبرص)</strong></li><li><strong>DFSA (دبي)</strong></li></ul><h2>الخطوة السادسة: الاستعانة بخبراء قانونيين</h2><img src="https://images.pexels.com/photos/5669619/pexels-photo-5669619.jpeg?auto=compress&cs=tinysrgb&w=800" alt="محامي متخصص" class="w-full rounded-xl my-6" /><h3>متى تحتاج محامياً؟</h3><ul><li>عندما تتجاوز الخسارة 10,000 دولار</li><li>عندما تكون الشركة في دولة أخرى</li><li>عندما فشلت المحاولات السابقة</li></ul><h2>الخطوة السابعة: الحذر من الاحتيال المزدوج</h2><img src="https://images.pexels.com/photos/6054750/pexels-photo-6054750.jpeg?auto=compress&cs=tinysrgb&w=800" alt="الاحتيال المزدوج" class="w-full rounded-xl my-6" /><div class="bg-red-50 border-r-4 border-red-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-red-800 mb-2">علامات شركات الاسترداد الاحتيالية</h4><ul class="text-gray-700"><li>طلب رسوم كبيرة مقدماً</li><li>وعود بضمان استرداد كامل</li><li>الضغط لاتخاذ قرار سريع</li></ul></div><h2>الجدول الزمني المتوقع</h2><table class="w-full border-collapse my-6"><thead><tr class="bg-gray-100"><th class="border p-3 text-right">الإجراء</th><th class="border p-3 text-right">المدة</th></tr></thead><tbody><tr><td class="border p-3">طلب Chargeback</td><td class="border p-3">1-2 أسبوع</td></tr><tr><td class="border p-3">تحقيق البنك</td><td class="border p-3">30-90 يوم</td></tr><tr><td class="border p-3">شكوى الجهة الرقابية</td><td class="border p-3">60-180 يوم</td></tr></tbody></table><h2>الخلاصة</h2><p>استرداد الأموال ممكن في كثير من الحالات، لكنه يتطلب صبراً وتنظيماً. سرعة التحرك هي العامل الأهم.</p>',
  updated_at = NOW()
WHERE slug = 'forex-fund-recovery-guide';

-- Article 2: Forex Scam Detection
UPDATE articles SET
  featured_image = 'https://images.pexels.com/photos/6801648/pexels-photo-6801648.jpeg?auto=compress&cs=tinysrgb&w=1200',
  excerpt = 'تعرف على أهم 10 علامات تحذيرية تساعدك على اكتشاف شركات الفوركس النصابة وتجنب الوقوع ضحية لعمليات الاحتيال المالي.',
  content = '<h2>مقدمة: لماذا تحتاج هذا الدليل؟</h2><p>سوق الفوركس هو أكبر سوق مالي في العالم، يتداول فيه أكثر من 6 تريليون دولار يومياً. هذه الضخامة تجذب المحتالين أيضاً.</p><img src="https://images.pexels.com/photos/6801648/pexels-photo-6801648.jpeg?auto=compress&cs=tinysrgb&w=800" alt="تحذيرات الفوركس" class="w-full rounded-xl my-6" /><p>في هذا الدليل، سنتعرف على 10 علامات تحذيرية.</p><h2>العلامة الأولى: وعود أرباح مضمونة</h2><p>أي شركة تعدك بأرباح شهرية ثابتة هي شركة احتيالية.</p><div class="bg-red-50 border-r-4 border-red-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-red-800 mb-2">أمثلة من وعود كاذبة:</h4><ul class="text-gray-700"><li>"ربح شهري مضمون 20%"</li><li>"لن تخسر أبداً مع نظامنا"</li><li>"استثمر 1000 واربح 5000"</li></ul></div><img src="https://images.pexels.com/photos/534216/pexels-photo-534216.jpeg?auto=compress&cs=tinysrgb&w=800" alt="أرباح الفوركس" class="w-full rounded-xl my-6" /><h2>العلامة الثانية: ترخيص مزيف</h2><p>التراخيص المعروضة غالباً تكون مزورة أو من جهة لا توفر حماية.</p><h3>كيف تتحقق؟</h3><ol><li>ادخل للموقع الرسمي للجهة الرقابية</li><li>ابحث باسم الشركة ورقم الترخيص</li><li>تأكد من تطابق الدومين</li></ol><h2>العلامة الثالثة: ضغط مستمر للإيداع</h2><img src="https://images.pexels.com/photos/6611418/pexels-photo-6611418.jpeg?auto=compress&cs=tinysrgb&w=800" alt="ضغط للإيداع" class="w-full rounded-xl my-6" /><div class="bg-amber-50 border-r-4 border-amber-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-amber-800 mb-2">علامات الضغط:</h4><ul class="text-gray-700"><li>اتصالات متكررة</li><li>"هذه الفرصة تنتهي اليوم"</li><li>"باقي مكان واحد في VIP"</li></ul></div><h2>العلامة الرابعة: مدير حساب يقرر بدلاً منك</h2><img src="https://images.pexels.com/photos/6476588/pexels-photo-6476588.jpeg?auto=compress&cs=tinysrgb&w=800" alt="مدير حساب" class="w-full rounded-xl my-6" /><div class="bg-blue-50 border-r-4 border-blue-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-blue-800 mb-2">القاعدة:</h4><p class="text-gray-700">الوسيط الحقيقي ينفذ أوامرك فقط.</p></div><h2>العلامة الخامسة: صعوبة السحب</h2><img src="https://images.pexels.com/photos/4386369/pexels-photo-4386369.jpeg?auto=compress&cs=tinysrgb&w=800" alt="صعوبة السحب" class="w-full rounded-xl my-6" /><h3>عقبات السحب:</h3><ul><li>طلب مستندات إضافية</li><li>تأخير الطلب</li><li>رسوم مبالغ فيها</li><li>ضرائب وهمية</li></ul><h2>العلامة السادسة: منصة غريبة</h2><div class="bg-red-50 border-r-4 border-red-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-red-800 mb-2">علامات منصة مشبوهة:</h4><ul class="text-gray-700"><li>تطبيق يُرسل عبر واتساب</li><li>غير موجودة في المتاجر الرسمية</li><li>أسعار تختلف عن المصادر الأخرى</li></ul></div><h2>العلامة السابعة: تقديرات غير واقعية</h2><p>"تحققت 95% من توقعاتنا!" - هذا كذب.</p><h2>العلامة الثامنة: غياب الشفافية</h2><img src="https://images.pexels.com/photos/5668858/pexels-photo-5668858.jpeg?auto=compress&cs=tinysrgb&w=800" alt="الشفافية" class="w-full rounded-xl my-6" /><h3>أسئلة يجب أن يكون لها إجابة:</h3><ul><li>أين المقر الفعلي؟</li><li>من هم المديرون؟</li><li>ما هي سياسة السحب؟</li></ul><h2>العلامة التاسعة: مراجعات مشبوهة</h2><p>احذر المراجعات المزيفة الإيجابية والحقيقية السلبية.</p><h2>العلامة العاشرة: تغيير الأسماء</h2><img src="https://images.pexels.com/photos/6054750/pexels-photo-6054750.jpeg?auto=compress&cs=tinysrgb&w=800" alt="تغيير الهوية" class="w-full rounded-xl my-6" /><h2>قائمة فحص قبل الإيداع</h2><table class="w-full border-collapse my-6"><thead><tr class="bg-gray-100"><th class="border p-3 text-right">البند</th><th class="border p-3 text-right">النتيجة</th></tr></thead><tbody><tr><td class="border p-3">الترخيص</td><td class="border p-3">موجود في الجهة الرقابية</td></tr><tr><td class="border p-3">السحب</td><td class="border p-3">تجربة ناجحة</td></tr><tr><td class="border p-3">المراجعات</td><td class="border p-3">إيجابية من مصادر موثوقة</td></tr></tbody></table><h2>الخلاصة</h2><p>الوقاية خير من العلاج. تعلم كيف تكشف شركات الفوركس النصابة قبل أن تودع أموالك.</p>',
  updated_at = NOW()
WHERE slug = 'how-to-detect-forex-scams';

-- Article 3: Forex Beginners Guide  
UPDATE articles SET
  featured_image = 'https://images.pexels.com/photos/7567705/pexels-photo-7567705.jpeg?auto=compress&cs=tinysrgb&w=1200',
  excerpt = 'إذا كنت ترغب في دخول عالم الفوركس، فهذا الدليل الشامل يشرح لك كل ما تحتاج معرفته خطوة بخطوة من الصفر حتى تنفيذ أول صفقة.',
  content = '<h2>مقدمة: لماذا تعلم الفوركس مهم؟</h2><p>سوق الفوركس هو أكبر سوق مالي في العالم بحجم تداول يومي يتجاوز 6 تريليون دولار.</p><img src="https://images.pexels.com/photos/7567705/pexels-photo-7567705.jpeg?auto=compress&cs=tinysrgb&w=800" alt="تداول الفوركس" class="w-full rounded-xl my-6" /><h2>الفصل الأول: ما هو الفوركس؟</h2><p>سوق عالمي لامركزي لتداول العملات. التداول 24 ساعة، 5 أيام أسبوعياً.</p><img src="https://images.pexels.com/photos/534216/pexels-photo-534216.jpeg?auto=compress&cs=tinysrgb&w=800" alt="سوق الفوركس" class="w-full rounded-xl my-6" /><h3>الأطراف الرئيسية:</h3><ul><li><strong>البنوك المركزية:</strong> تتحكم في السياسة النقدية</li><li><strong>البنوك التجارية:</strong> أكبر محرك للسوق</li><li><strong>المتداولون الأفراد:</strong> مثلك أنت</li></ul><h3>أزواج العملات:</h3><div class="bg-blue-50 border-r-4 border-blue-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-blue-800 mb-2">أمثلة:</h4><ul class="text-gray-700"><li><strong>EUR/USD:</strong> يورو/دولار</li><li><strong>GBP/USD:</strong> جنيه/دولار</li><li><strong>USD/JPY:</strong> دولار/ين ياباني</li></ul></div><h2>الفصل الثاني: آلية التداول</h2><img src="https://images.pexels.com/photos/6476588/pexels-photo-6476588.jpeg?auto=compress&cs=tinysrgb&w=800" alt="آلية التداول" class="w-full rounded-xl my-6" /><h3>مفاهيم أساسية:</h3><h4>النقطة (Pip)</h4><p>أصغر وحدة تغير في السعر.</p><h4>الرافعة المالية</h4><p>تسمح بالتحكم بمبلغ أكبر من رأس المال.</p><div class="bg-amber-50 border-r-4 border-amber-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-amber-800 mb-2">تحذير:</h4><p class="text-gray-700">الرافعة سلاح ذو حدين.</p></div><h2>الفصل الثالث: اختيار الوسيط</h2><img src="https://images.pexels.com/photos/5668858/pexels-photo-5668858.jpeg?auto=compress&cs=tinysrgb&w=800" alt="اختيار الوسيط" class="w-full rounded-xl my-6" /><h3>المعايير:</h3><ul><li><strong>الترخيص:</strong> FCA، ASIC، CySEC</li><li><strong>فروق الأسعار:</strong> كلما قلت كان أفضل</li><li><strong>سهولة السحب:</strong> جرب قبل زيادة الإيداع</li><li><strong>المنصة:</strong> MetaTrader 4/5</li></ul><h2>الفصل الرابع: فتح حساب</h2><img src="https://images.pexels.com/photos/6611418/pexels-photo-6611418.jpeg?auto=compress&cs=tinysrgb&w=800" alt="فتح حساب" class="w-full rounded-xl my-6" /><ol><li><strong>التسجيل:</strong> أدخل بياناتك</li><li><strong>التحقق:</strong> حمل الهوية</li><li><strong>اختيار الحساب:</strong> تجريبي أو حقيقي</li><li><strong>الإيداع:</strong> ابدأ بمبلغ صغير</li></ol><div class="bg-green-50 border-r-4 border-green-500 p-4 my-4 rounded-lg"><p class="text-gray-700">ابدأ بحساب تجريبي لمدة شهر.</p></div><h2>الفصل الخامس: أساسيات التحليل</h2><h3>التحليل الأساسي</h3><ul><li>قرارات الفائدة</li><li>معدلات التضخم</li><li>الأحداث السياسية</li></ul><h3>التحليل الفني</h3><ul><li>مستويات الدعم والمقاومة</li><li>الاتجاهات</li><li>المؤشرات (RSI، MACD)</li></ul><img src="https://images.pexels.com/photos/6801648/pexels-photo-6801648.jpeg?auto=compress&cs=tinysrgb&w=800" alt="التحليل الفني" class="w-full rounded-xl my-6" /><h2>الفصل السادس: إدارة المخاطر</h2><ul><li>لا تخاطر بأكثر من 1-2% في صفقة</li><li>استخدم وقف الخسارة دائماً</li><li>استهدف عائد ضعفي المخاطرة</li></ul><div class="bg-red-50 border-r-4 border-red-500 p-4 my-4 rounded-lg"><h4 class="font-bold text-red-800 mb-2">قاعدة:</h4><p class="text-gray-700">لا تخاطر بأموال تحتاجها للحياة.</p></div><h2>الفصل السابع: أول صفقة</h2><img src="https://images.pexels.com/photos/7308955/pexels-photo-7308955.jpeg?auto=compress&cs=tinysrgb&w=800" alt="أول صفقة" class="w-full rounded-xl my-6" /><ol><li>اختر زوج عملات مألوف</li><li>قم بالتحليل</li><li>حدد نقطة الدخول</li><li>ضع وقف الخسارة</li><li>حدد هدف الربح</li><li>نفذ الصفقة</li></ol><h2>الفصل الثامن: الأخطاء الشائعة</h2><ul><li><strong>التداول العاطفي</strong></li><li><strong>الإفراط في التداول</strong></li><li><strong>إهمال وقف الخسارة</strong></li><li><strong>الرافعة العالية</strong></li></ul><h2>الفصل التاسع: حماية نفسك</h2><img src="https://images.pexels.com/photos/6054750/pexels-photo-6054750.jpeg?auto=compress&cs=tinysrgb&w=800" alt="الحماية" class="w-full rounded-xl my-6" /><h3>علامات الاحتيال:</h3><ul><li>وعود بأرباح مضمونة</li><li>ضغط للإيداع</li><li>ترخيص مزيف</li><li>صعوبة السحب</li></ul><h2>الخلاصة</h2><p>تداول الفوركس رحلة تتطلب صبراً وتعليماً. ابدأ بالحساب التجريبي واختر وسيطاً مرخصاً.</p>',
  updated_at = NOW()
WHERE slug = 'forex-trading-beginners-guide';

